INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'e9920ace-c439-4d9b-8970-b850d8835ecd',
  '00000000-0000-0000-0000-000000000001',
  $escape$Bitcoin Script - Stack-Based and Intentionally Limited$escape$,
  $escape$Bitcoin Script is a stack-based, intentionally limited programming language used for scripting transactions on the Bitcoin blockchain. It's designed for simplicity and security. Two essential concepts in Bitcoin Script are Pay-to-Public-Key-Hash (P2PKH) and Pay-to-Script-Hash (P2SH). P2PKH ensures that a transaction can be spent by anyone who knows the private key corresponding to a specific public key. P2SH allows a script to be hashed and stored in the blockchain, making it possible to create multisignature wallets. In Bitcoin Script, multisignature wallets can be implemented using the CHECKSIG and CHECKMULTISIG operators.$escape$,
  NULL,
  NULL,
